    pub hired_at: NaiveDate,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct DailyBusinessMetrics {
    pub date: NaiveDate,
    pub revenue_gaming_paise: i64,
    pub revenue_cafe_paise: i64,
